import{_ as o,o as a,c as i,ag as l}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Dotfiles 소개 (KO)","titleTemplate":":title","description":"차세대 셸 구성. 고성능, 보안, AI 네이티브. Chezmoi로 관리됩니다.","frontmatter":{"title":"Dotfiles 소개","description":"차세대 셸 구성. 고성능, 보안, AI 네이티브. Chezmoi로 관리됩니다.","lang":"ko-KR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Dotfiles 소개 preview","canonical":"/ko/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Dotfiles 소개","pageType":"docs","schemaType":"WebPage","metaTitle":"Dotfiles 소개 - Dotfiles (KR)","permalink":"/ko/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, configuration, automation, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"차세대 셸 구성. 고성능, 보안, AI 네이티브. Chezmoi로 관리됩니다."},{"name":"twitter:title","content":"Dotfiles 소개"},{"name":"og:title","content":"Dotfiles 소개"},{"name":"og:description","content":"차세대 셸 구성. 고성능, 보안, AI 네이티브. Chezmoi로 관리됩니다."},{"name":"og:image:alt","content":"Dotfiles - 셸 라이프에 맞게 간단하게 설계됨"},{"name":"og:locale","content":"ko_KR"}]},"headers":[],"relativePath":"ko/about/index.md","filePath":"ko/about/index.md","lastUpdated":1773010926000}'),t={name:"ko/about/index.md"};function s(d,e,n,c,r,h){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="dotfiles-소개" tabindex="-1">Dotfiles 소개 <a class="header-anchor" href="#dotfiles-소개" aria-label="Permalink to &quot;Dotfiles 소개&quot;">​</a></h1><p>셸 구성의 현대적 표준. 안전한 크로스 플랫폼 환경 관리를 위해 <strong>Chezmoi</strong> 기반으로 구축되었습니다.</p><h2 id="발견하기" tabindex="-1">발견하기 <a class="header-anchor" href="#발견하기" aria-label="Permalink to &quot;발견하기&quot;">​</a></h2><p>Dotfiles v0.2.495는 터미널을 강력하고 통합된 작업 공간으로 변환합니다. 복잡한 Makefile이나 심볼릭 링크 스크립트에 의존하는 레거시 dotfiles와 달리, Dotfiles는 원자적이고 빠르며 재현 가능한 템플릿 기반 접근 방식을 사용합니다.</p><h3 id="새로운-기능" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li><strong>모던 코어</strong> — 고성능 Rust 대안으로 레거시 Unix 도구를 대체: <ul><li><strong>Atuin</strong> 셸 히스토리</li><li><strong>Yazi</strong> 파일 관리</li><li><strong>Zellij</strong> 터미널 멀티플렉싱</li><li><strong>Ghostty</strong> GPU 가속 터미널</li><li><strong>NeoVim</strong> 모던 에디팅</li></ul></li><li><strong>네이티브 보안</strong> — 서드파티 에이전트 없는 완전 네이티브 SSH 서명</li><li><strong>인터랙티브 모드</strong> — 새로운 <code>dot learn</code> 명령으로 기능 안내</li></ul><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><h3 id="요구-사항" tabindex="-1">요구 사항 <a class="header-anchor" href="#요구-사항" aria-label="Permalink to &quot;요구 사항&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong>, 또는 <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> 및 <strong>Git</strong></li><li><strong>Chezmoi</strong> (자동 설치)</li><li><strong>Nerd Font</strong> (터미널 아이콘용)</li></ul><h3 id="설치" tabindex="-1">설치 <a class="header-anchor" href="#설치" aria-label="Permalink to &quot;설치&quot;">​</a></h3><p>단일 명령으로 전체 스위트를 설치합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>설치 프로그램은 다음을 수행합니다:</p><ol><li><code>chezmoi</code> 바이너리 설치</li><li>저장소 복제</li><li>Homebrew (macOS) 또는 Apt (Linux)를 통해 필요한 패키지 설치</li><li>구성 적용</li></ol><h3 id="탐색" tabindex="-1">탐색 <a class="header-anchor" href="#탐색" aria-label="Permalink to &quot;탐색&quot;">​</a></h3><p>설치 후 터미널을 다시 시작하고 실행합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>새 환경의 인터랙티브 투어가 시작됩니다.</p><h2 id="사용자화" tabindex="-1">사용자화 <a class="header-anchor" href="#사용자화" aria-label="Permalink to &quot;사용자화&quot;">​</a></h2><p>구성은 <code>~/.local/share/chezmoi</code>에 있습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # 셸 진입점</span></span>
<span class="line"><span>├── dot_config/             # XDG Base Config (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # 셸 히스토리</span></span>
<span class="line"><span>│   ├── ghostty/            # 터미널 에뮬레이터</span></span>
<span class="line"><span>│   ├── git/                # Git 구성</span></span>
<span class="line"><span>│   ├── yazi/               # 파일 관리자</span></span>
<span class="line"><span>│   ├── zellij/             # 터미널 멀티플렉서</span></span>
<span class="line"><span>│   ├── zsh/                # Zsh 구성</span></span>
<span class="line"><span>│   └── shell/              # 공유 별칭 및 경로</span></span>
<span class="line"><span>├── provision/              # 라이프사이클 스크립트</span></span>
<span class="line"><span>├── install.sh              # 범용 설치 프로그램</span></span>
<span class="line"><span>└── docs/                   # 문서</span></span></code></pre></div><h2 id="핵심-명령어" tabindex="-1">핵심 명령어 <a class="header-anchor" href="#핵심-명령어" aria-label="Permalink to &quot;핵심 명령어&quot;">​</a></h2><p><code>dot</code> CLI는 53개의 명령어를 카테고리별로 제공합니다.</p><h3 id="코어" tabindex="-1">코어 <a class="header-anchor" href="#코어" aria-label="Permalink to &quot;코어&quot;">​</a></h3><ul><li><code>dot apply</code> — 구성 변경 사항을 적용합니다.</li><li><code>dot sync</code> — 최신 저장소 상태를 가져와 적용합니다.</li><li><code>dot update</code> — 저장소를 업데이트하고 캐시를 예열합니다.</li><li><code>dot add</code> — 새 파일을 Chezmoi 소스에 추가합니다.</li><li><code>dot diff</code> — 적용 전 보류 중인 변경 사항을 표시합니다.</li><li><code>dot status</code> — 관리 대상 파일 상태를 표시합니다.</li><li><code>dot remove</code> — 파일 관리를 해제하고 소스 항목을 삭제합니다.</li><li><code>dot cd</code> — Chezmoi 소스 디렉토리에서 셸을 엽니다.</li><li><code>dot edit</code> — 관리 대상 파일을 편집기에서 엽니다.</li><li><code>dot clean-cache</code> — 임시 캐시를 삭제합니다.</li><li><code>dot prewarm</code> — 빠른 셸 시작을 위해 캐시를 미리 채웁니다.</li></ul><h3 id="진단" tabindex="-1">진단 <a class="header-anchor" href="#진단" aria-label="Permalink to &quot;진단&quot;">​</a></h3><ul><li><code>dot doctor</code> — 경로, 도구 및 셸 상태를 검증합니다.</li><li><code>dot heal</code> — 누락되거나 손상된 상태를 자동으로 복구합니다.</li><li><code>dot health</code> — 경량 헬스 프로브를 실행합니다.</li><li><code>dot verify</code> — 소스 대비 파일 무결성을 확인합니다.</li><li><code>dot scorecard</code> — 구성 품질 점수를 출력합니다.</li><li><code>dot snapshot</code> — 나중 비교를 위해 현재 상태를 캡처합니다.</li><li><code>dot smoke-test</code> — 핵심 도구 체인을 엔드투엔드로 검증합니다.</li><li><code>dot chaos</code> — 자가 치유 테스트를 위해 장애를 주입합니다.</li><li><code>dot bundle</code> — 이식 가능한 구성 번들을 내보냅니다.</li><li><code>dot rollback</code> — 이전 스냅샷으로 되돌립니다.</li><li><code>dot drift</code> — 관리 대상 파일의 예기치 않은 변경을 감지합니다.</li><li><code>dot history</code> — apply/sync 히스토리 로그를 표시합니다.</li><li><code>dot benchmark</code> — 셸 시작 시간을 측정합니다.</li><li><code>dot perf</code> — 느린 셸 초기화를 프로파일링합니다.</li></ul><h3 id="외관" tabindex="-1">외관 <a class="header-anchor" href="#외관" aria-label="Permalink to &quot;외관&quot;">​</a></h3><ul><li><code>dot theme</code> — 터미널 색상 테마를 전환합니다.</li><li><code>dot wallpaper</code> — 바탕 화면 배경을 설정합니다 (macOS).</li><li><code>dot fonts</code> — Nerd Fonts를 설치하거나 업데이트합니다.</li><li><code>dot tune</code> — UI 밀도와 프롬프트 스타일을 조정합니다.</li></ul><h3 id="보안" tabindex="-1">보안 <a class="header-anchor" href="#보안" aria-label="Permalink to &quot;보안&quot;">​</a></h3><ul><li><code>dot backup</code> — 암호화된 구성 백업을 생성합니다.</li><li><code>dot encrypt-check</code> — 저장된 시크릿의 암호화를 확인합니다.</li><li><code>dot firewall</code> — 호스트 방화벽 규칙을 구성합니다.</li><li><code>dot telemetry</code> — 익명 사용 텔레메트리를 제어합니다.</li><li><code>dot dns-doh</code> — DNS-over-HTTPS를 활성화합니다.</li><li><code>dot lock-screen</code> — 화면을 즉시 잠급니다.</li><li><code>dot usb-safety</code> — USB 대용량 저장소 자동 마운트를 제한합니다.</li></ul><h3 id="시크릿" tabindex="-1">시크릿 <a class="header-anchor" href="#시크릿" aria-label="Permalink to &quot;시크릿&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — 시크릿 백엔드를 초기화합니다 (age / GPG).</li><li><code>dot secrets</code> — 암호화된 시크릿 항목을 나열합니다.</li><li><code>dot secrets-create</code> — 새 암호화된 시크릿을 생성합니다.</li><li><code>dot ssh-key</code> — SSH 키 쌍을 생성하거나 교체합니다.</li><li><code>dot ssh-cert</code> — CA에서 SSH 인증서를 요청합니다.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — 대화형 AI 어시스턴트 세션을 엽니다.</li><li><code>dot ai-setup</code> — AI 제공업체의 API 키를 구성합니다.</li><li><code>dot ai-query</code> — AI 모델에 일회성 프롬프트를 전송합니다.</li><li>AI 도구 래퍼: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="도구" tabindex="-1">도구 <a class="header-anchor" href="#도구" aria-label="Permalink to &quot;도구&quot;">​</a></h3><ul><li><code>dot tools</code> — 번들된 CLI 대체 도구와 상태를 나열합니다.</li><li><code>dot new</code> — 새 별칭 또는 함수 파일을 생성합니다.</li><li><code>dot sandbox</code> — 일회용 샌드박스 셸을 엽니다.</li><li><code>dot keys</code> — 현재 키 바인딩을 표시합니다.</li><li><code>dot learn</code> — 대화형 튜토리얼을 시작합니다.</li></ul><h3 id="메타" tabindex="-1">메타 <a class="header-anchor" href="#메타" aria-label="Permalink to &quot;메타&quot;">​</a></h3><ul><li><code>dot upgrade</code> — Dotfiles를 최신 릴리스로 업그레이드합니다.</li><li><code>dot packages</code> — Dotfiles가 관리하는 설치된 패키지를 나열합니다.</li><li><code>dot version</code> / <code>dot help</code> — 버전 또는 사용법 정보를 출력합니다</li></ul><h2 id="기여" tabindex="-1">기여 <a class="header-anchor" href="#기여" aria-label="Permalink to &quot;기여&quot;">​</a></h2><p>커뮤니티에 참여하세요. <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">행동 강령</a> 및 <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">기여 가이드라인</a>을 검토해 주세요.</p>`,41)])])}const g=o(t,[["render",s]]);export{u as __pageData,g as default};
